const staticData = $getWorkflowStaticData('global');
if (!staticData.measurements) staticData.measurements = [];
if (!staticData.alerts) staticData.alerts = [];
if (!staticData.serp_history) staticData.serp_history = [];

return [{ json: {
  brightdata_body: JSON.stringify({
    zone: 'serp_api1',
    url: 'https://www.google.com/search?q=Sina+Bari+MD&gl=us&hl=en',
    format: 'json',
  }),
  brightdata_body_p2: JSON.stringify({
    zone: 'serp_api1',
    url: 'https://www.google.com/search?q=Sina+Bari+MD&gl=us&hl=en&start=10',
    format: 'json',
  }),
  measured_at: new Date().toISOString(),
} }];

const upstream = $('Build SERP Queries').first().json;
const page1Body = $('BrightData Page 1').first().json.body || '';
const page2Body = $json.body || '';

function parseGoogleHTML(html, startPos) {
  const results = [];
  // Extract hrefs (non-Google external URLs)
  const hrefPattern = /href="(https?:\/\/(?!www\.google\.|webcache\.|translate\.google\.|accounts\.google|support\.google|maps\.google|policies\.google|www\.gstatic|consent\.google)[^"]+)"/g;
  const seenBases = new Set();
  let match;
  while ((match = hrefPattern.exec(html)) !== null) {
    let url = match[1].replace(/&amp;/g, '&');
    const base = url.split('#')[0].split('&sa=')[0];
    if (seenBases.has(base) || base.endsWith('/search')) continue;
    seenBases.add(base);
    const domainMatch = base.match(/https?:\/\/(?:www\.)?([^\/]+)/);
    results.push({ url: base, domain: domainMatch ? domainMatch[1] : '' });
  }
  // Get titles
  const titlePattern = /<h3[^>]*>(.*?)<\/h3>/g;
  const titles = [];
  while ((match = titlePattern.exec(html)) !== null) {
    titles.push(match[1].replace(/<[^>]+>/g, '').replace(/&amp;/g, '&').replace(/&#39;/g, "'").replace(/&quot;/g, '"'));
  }
  // Assign positions and titles
  return results.map((r, i) => ({ ...r, title: titles[i] || '', position: startPos + i }));
}

const page1 = parseGoogleHTML(page1Body, 1);
const page2 = parseGoogleHTML(page2Body, page1.length + 1);
const allResults = [...page1, ...page2];

const ownDomains = ['sinabarimd.com', 'sinabari.net', 'sinabariplasticsurgery.com', 'drsinabari.com'];
const knownProfiles = [
  'linkedin.com','facebook.com','instagram.com','twitter.com','x.com','bsky.app',
  'doximity.com','crunchbase.com','scholar.google.com','muckrack.com','about.me',
  'wikidata.org','techcrunch.com','healthgrades.com','vitals.com',
  'pmwcintl.com','open.spotify.com','san.com',
  'behance.net','linktr.ee','youtube.com','pinterest.com','mystrikingly.com',
  'wordpress.com','medium.com','tumblr.com','blogspot.com','slides.com',
  'flipboard.com','sites.google.com','webflow.io',
  'triberr.com','disqus.com','producthunt.com','github.com',
  'quora.com','flickr.com','vocal.media','minds.com',
  'findatopdoc.com','ratemds.com','doctor.com','stackoverflow.com',
  'yelp.com','mapquest.com',
  'einnews.com','einpresswire.com','icrowdnewswire.com','ipsnews.net',
  'wboc.com','scrubsmag.com','deadlinenews.co.uk','marketwatch.com',
  'techbullion.com',
];

const mStaticData = $getWorkflowStaticData('global');
const negativeTargets = mStaticData.negative_targets || [];

const results = allResults.map(r => {
  const isOwn = ownDomains.some(d => r.domain === d || r.domain.endsWith('.' + d));
  const isKnown = knownProfiles.some(d => r.domain === d || r.domain.endsWith('.' + d));
  const isNeg = negativeTargets.some(t => (t.domain && r.domain.includes(t.domain)) || (t.url && r.url.includes(t.url || '___')));
  return { ...r, type: isOwn ? 'owned' : isNeg ? 'negative' : isKnown ? 'known_profile' : 'other' };
});

const owned = results.filter(r => r.type === 'owned');
const negatives = results.filter(r => r.type === 'negative');
const competitors = results.filter(r => r.type === 'other');
const known = results.filter(r => r.type === 'known_profile');

return [{ json: {
  ...upstream,
  serp: {
    query: 'Sina Bari MD',
    source: 'brightdata_residential',
    total_results: results.length,
    owned_count: owned.length,
    known_profile_count: known.length,
    negative_count: negatives.length,
    competitor_count: competitors.length,
    highest_owned_position: owned.length ? owned[0].position : null,
    owned_positions: owned,
    known_positions: known,
    competitor_positions: competitors,
    negative_results: negatives,
    all_results: results,
    suppression_alerts: negatives,
  },
} }];

const { serp, measured_at } = $json;
const staticData = $getWorkflowStaticData('global');
const measurement = { measured_at, source: 'serpapi_google', serp };

const prev = staticData.measurements.length ? staticData.measurements[staticData.measurements.length - 1] : null;

// Fresh alerts for THIS measurement — replaces all prior alerts
const newAlerts = [];

// Change-based alerts (only if we have a previous measurement to compare)
if (prev && prev.serp) {
  const prevOwned = prev.serp.owned_count || 0;
  const currOwned = serp.owned_count || 0;
  if (currOwned < prevOwned) {
    newAlerts.push({ type: 'serp_decline', severity: 'high',
      message: `Owned SERP results decreased: ${prevOwned} → ${currOwned}`, measured_at });
  }
  if (currOwned > prevOwned) {
    newAlerts.push({ type: 'serp_gain', severity: 'info',
      message: `Owned SERP results increased: ${prevOwned} → ${currOwned}`, measured_at });
  }
  const prevBest = prev.serp.highest_owned_position;
  const currBest = serp.highest_owned_position;
  if (prevBest && currBest && currBest > prevBest + 2) {
    newAlerts.push({ type: 'position_drop', severity: 'high',
      message: `Best owned position dropped: #${prevBest} → #${currBest}`, measured_at });
  }
}

// State-based alerts (reflect current SERP snapshot — regenerated each measurement)
const topComps = (serp.competitor_positions || []).filter(c => c.position <= 5);
for (const c of topComps) {
  newAlerts.push({ type: 'unknown_competitor', severity: 'medium',
    message: `Non-owned result at #${c.position}: "${c.title}" (${c.domain})`, measured_at });
}

const sinabarimdPos = (serp.owned_positions || []).find(r => r.domain.includes('sinabarimd.com'));
if (sinabarimdPos && sinabarimdPos.position > 5) {
  newAlerts.push({ type: 'canonical_weak', severity: 'medium',
    message: `sinabarimd.com at #${sinabarimdPos.position} — canonical hub should be top 5`, measured_at });
}

const suppressionAlerts = serp.suppression_alerts || [];
for (const sa of suppressionAlerts) {
  newAlerts.push({ type: 'suppression_target', severity: 'high',
    message: `Suppression target detected at #${sa.position}: "${sa.title}" (${sa.domain})`, measured_at });
}

// Store measurement
staticData.measurements.push(measurement);
if (staticData.measurements.length > 12) staticData.measurements = staticData.measurements.slice(-12);

// REPLACE alerts entirely with fresh snapshot — no stale accumulation
staticData.alerts = newAlerts;

staticData.serp_history.push({
  date: measured_at,
  owned_count: serp.owned_count,
  highest_position: serp.highest_owned_position,
  total_results: serp.total_results,
});
if (staticData.serp_history.length > 52) staticData.serp_history = staticData.serp_history.slice(-52);

return [{ json: {
  success: true,
  measured_at,
  source: 'serpapi_google',
  serp_owned: serp.owned_count,
  serp_total: serp.total_results,
  highest_position: serp.highest_owned_position,
  new_alerts: newAlerts.length,
  alerts: newAlerts,
} }];

const staticData = $getWorkflowStaticData('global');
const measurements = staticData.measurements || [];
const alerts = staticData.alerts || [];
const history = staticData.serp_history || [];
const latest = measurements.length ? measurements[measurements.length - 1] : null;
const negativeTargets = staticData.negative_targets || [];

return [{ json: {
  latest_measurement: latest,
  measurement_count: measurements.length,
  active_alerts: alerts.filter(a => a.severity === 'high' || a.severity === 'medium'),
  all_alerts: alerts.slice(0, 20),
  serp_trend: history.slice(-12),
  last_measured: latest?.measured_at || 'never',
  negative_targets: negativeTargets,
} }];

const body = $json.body || $json;
const measurement = body.measurement;
if (!measurement) return [{ json: { error: true, message: 'No measurement data provided' } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.measurements) staticData.measurements = [];
if (!staticData.alerts) staticData.alerts = [];
if (!staticData.serp_history) staticData.serp_history = [];

// Compare with previous for alerts
const prev = staticData.measurements.length ? staticData.measurements[staticData.measurements.length - 1] : null;
const newAlerts = [];
const bp = measurement.branded_positions || {};

if (prev && prev.branded_positions) {
  for (const [sid, pos] of Object.entries(bp)) {
    const prevPos = prev.branded_positions[sid];
    if (prevPos && pos > prevPos + 3) {
      newAlerts.push({ type: 'branded_decline', severity: 'high',
        message: `${sid}: branded position dropped ${Math.round(prevPos)} → ${Math.round(pos)}`, measured_at: measurement.measured_at });
    }
    if (prevPos && pos < prevPos - 3) {
      newAlerts.push({ type: 'branded_gain', severity: 'info',
        message: `${sid}: branded position improved ${Math.round(prevPos)} → ${Math.round(pos)}`, measured_at: measurement.measured_at });
    }
  }
}

if (bp.sinabarimd && bp.sinabarimd > 10) {
  newAlerts.push({ type: 'canonical_weak', severity: 'medium',
    message: `sinabarimd.com branded position is ${Math.round(bp.sinabarimd)} — canonical hub should be top 10`,
    measured_at: measurement.measured_at });
}

if (prev && prev.total_clicks > 0) {
  const change = ((measurement.total_clicks || 0) - prev.total_clicks) / prev.total_clicks;
  if (change < -0.2) {
    newAlerts.push({ type: 'traffic_decline', severity: 'high',
      message: `Clicks declined ${Math.round(change * 100)}%`, measured_at: measurement.measured_at });
  }
}

staticData.measurements.push(measurement);
if (staticData.measurements.length > 12) staticData.measurements = staticData.measurements.slice(-12);
staticData.alerts = [...newAlerts, ...(staticData.alerts || [])].slice(0, 50);
staticData.serp_history.push({
  date: measurement.measured_at,
  total_clicks: measurement.total_clicks,
  total_impressions: measurement.total_impressions,
  branded_positions: measurement.branded_positions,
});
if (staticData.serp_history.length > 52) staticData.serp_history = staticData.serp_history.slice(-52);

return [{ json: {
  success: true,
  measured_at: measurement.measured_at,
  total_clicks: measurement.total_clicks,
  total_impressions: measurement.total_impressions,
  branded_positions: measurement.branded_positions,
  new_alerts: newAlerts.length,
  alerts: newAlerts,
} }];

const body = $json.body || $json;
const { action, domain, url, title, position } = body;
const staticData = $getWorkflowStaticData('global');

if (action === 'clear_alerts') {
  const count = (staticData.alerts || []).length;
  staticData.alerts = [];
  return [{ json: { success: true, action: 'clear_alerts', cleared: count } }];
}

if (action === 'mark_negative') {
  if (!domain && !url) return [{ json: { error: true, message: 'domain or url required' } }];
  if (!staticData.negative_targets) staticData.negative_targets = [];
  const target = {
    domain: domain || '',
    url: url || '',
    title: title || '',
    marked_at: new Date().toISOString(),
    first_seen_position: position || null,
  };
  // Avoid duplicates
  if (!staticData.negative_targets.find(t => t.domain === target.domain && t.url === target.url)) {
    staticData.negative_targets.push(target);
  }
  return [{ json: { success: true, action: 'mark_negative', target, total_targets: staticData.negative_targets.length } }];
}

if (action === 'unmark_negative') {
  if (!staticData.negative_targets) return [{ json: { success: true, action: 'unmark_negative', removed: 0 } }];
  const before = staticData.negative_targets.length;
  staticData.negative_targets = staticData.negative_targets.filter(t => t.domain !== domain && t.url !== url);
  return [{ json: { success: true, action: 'unmark_negative', removed: before - staticData.negative_targets.length } }];
}

if (action === 'list_negative') {
  return [{ json: { negative_targets: staticData.negative_targets || [] } }];
}

return [{ json: { error: true, message: 'Unknown action. Use: clear_alerts, mark_negative, unmark_negative, list_negative' } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.web20_scans) staticData.web20_scans = [];
if (!staticData.web20_alerts) staticData.web20_alerts = [];

const PROFILES = [
  {id:'strikingly', url:'https://sina-barimd.mystrikingly.com/', name:'Strikingly', priority:'critical'},
  {id:'wordpress0', url:'https://sinabarimd0.wordpress.com/', name:'WordPress (sinabarimd0)', priority:'critical'},
  {id:'crunchbase', url:'https://www.crunchbase.com/person/sina-bari-md-f5c7', name:'Crunchbase', priority:'critical'},
  {id:'wordpress', url:'https://sinabarimd.wordpress.com/', name:'WordPress (sinabarimd)', priority:'critical'},
  {id:'tumblr', url:'https://sina-barimd.tumblr.com/', name:'Tumblr', priority:'critical'},
  {id:'linkedin', url:'https://www.linkedin.com/in/sinabarimd', name:'LinkedIn', priority:'high'},
  {id:'doximity', url:'https://www.doximity.com/cv/sinabarimd', name:'Doximity', priority:'high'},
  {id:'instagram', url:'https://www.instagram.com/sina.bari/', name:'Instagram', priority:'high'},
  {id:'healthgrades', url:'https://www.healthgrades.com/physician/dr-sina-bari-xj7q6', name:'Healthgrades', priority:'high'},
  {id:'facebook', url:'https://www.facebook.com/SinaBariMD', name:'Facebook', priority:'high'},
  {id:'medium', url:'https://sina-barimd.medium.com/', name:'Medium', priority:'high'},
  {id:'youtube', url:'https://www.youtube.com/channel/UCtepx5Hdpt3W7Rrx5cgF9zQ/', name:'YouTube', priority:'high'},
  {id:'quora', url:'https://www.quora.com/profile/Sina-Bari-MD', name:'Quora', priority:'high'},
  {id:'twitter', url:'https://x.com/sinabariMD', name:'Twitter/X', priority:'high'},
  {id:'about_me', url:'https://about.me/sina-barimd', name:'About.me', priority:'medium'},
  {id:'linktree', url:'https://linktr.ee/sinabarimd', name:'Linktree', priority:'medium'},
  {id:'webflow', url:'https://sinabarimd.webflow.io/', name:'Webflow', priority:'medium'},
  {id:'behance', url:'https://www.behance.net/sina-bari-md', name:'Behance', priority:'low'},
  {id:'github', url:'https://github.com/sinabarimd', name:'GitHub', priority:'low'},
  {id:'bluesky', url:'https://bsky.app/profile/sinabarimd.bsky.social', name:'Bluesky', priority:'low'},
  {id:'slides', url:'https://slides.com/sinabarimd', name:'Slides', priority:'low'},
  {id:'pinterest', url:'https://www.pinterest.com/sinabarimd0/', name:'Pinterest', priority:'low'},
  {id:'flipboard', url:'https://flipboard.com/@sinabarimd0', name:'Flipboard', priority:'low'},
  {id:'findatopdoc', url:'https://www.findatopdoc.com/doctor/85024348-Sina-Bari-Plastic-Surgeon', name:'FindATopDoc', priority:'low'},
];

const results = [];
const newAlerts = [];
const now = new Date().toISOString();

for (const profile of PROFILES) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: profile.url,
      returnFullResponse: true,
      followAllRedirects: true,
      timeout: 10000,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; ReputationEngine/1.0)' },
    });
    const status = resp.statusCode || 0;
    const ok = status >= 200 && status < 400;
    const body = typeof resp.body === 'string' ? resp.body : '';

    // Check 1: Hub link present
    const hasSinabarimd = body.includes('sinabarimd.com');

    // Check 2: Key entity terms present
    const hasStanford = body.toLowerCase().includes('stanford');
    const hasSurgeon = body.toLowerCase().includes('surgeon');
    const hasAI = body.toLowerCase().includes('healthcare ai') || body.toLowerCase().includes('artificial intelligence');
    const entityScore = (hasStanford ? 1 : 0) + (hasSurgeon ? 1 : 0) + (hasAI ? 1 : 0);

    // Check 3: Content freshness — look for date indicators
    const currentYear = new Date().getFullYear();
    const hasCurrentYear = body.includes(String(currentYear));
    const hasLastYear = body.includes(String(currentYear - 1));
    const freshness = hasCurrentYear ? 'current' : hasLastYear ? 'recent' : 'stale';

    // Check 4: HTTPS
    const isHttps = profile.url.startsWith('https://');

    // Check 5: Content length (proxy for profile completeness)
    const contentLength = body.length;
    const isSubstantial = contentLength > 5000;

    results.push({
      id: profile.id, name: profile.name, url: profile.url,
      priority: profile.priority, status, ok,
      hub_link: hasSinabarimd,
      entity_terms: { stanford: hasStanford, surgeon: hasSurgeon, ai: hasAI, score: entityScore },
      freshness,
      https: isHttps,
      substantial_content: isSubstantial,
      content_length: contentLength,
    });

    // Generate alerts
    if (!ok) {
      newAlerts.push({ type: 'profile_down', severity: profile.priority === 'critical' ? 'high' : 'medium',
        message: `${profile.name} returned ${status}`, url: profile.url, checked_at: now });
    }
    if (ok && !hasSinabarimd && profile.priority !== 'low') {
      newAlerts.push({ type: 'missing_hub_link', severity: 'medium',
        message: `${profile.name}: no sinabarimd.com link detected`, url: profile.url, checked_at: now });
    }
    if (ok && freshness === 'stale' && profile.priority !== 'low') {
      newAlerts.push({ type: 'stale_content', severity: 'low',
        message: `${profile.name}: content appears stale (no ${currentYear} or ${currentYear-1} dates found)`, url: profile.url, checked_at: now });
    }
    if (ok && entityScore === 0 && profile.priority !== 'low') {
      newAlerts.push({ type: 'missing_entity_terms', severity: 'low',
        message: `${profile.name}: no Stanford/surgeon/AI keywords detected`, url: profile.url, checked_at: now });
    }
  } catch (e) {
    results.push({
      id: profile.id, name: profile.name, url: profile.url,
      priority: profile.priority, status: 0, ok: false, hub_link: false,
      entity_terms: { score: 0 }, freshness: 'unknown', https: true, substantial_content: false,
      error: String(e.message || e).slice(0, 100),
    });
    if (profile.priority !== 'low') {
      newAlerts.push({ type: 'profile_error', severity: 'medium',
        message: `${profile.name}: ${String(e.message || e).slice(0, 60)}`, url: profile.url, checked_at: now });
    }
  }
}

// Summary stats
const live = results.filter(r => r.ok).length;
const withHub = results.filter(r => r.hub_link).length;
const fresh = results.filter(r => r.freshness === 'current').length;
const stale = results.filter(r => r.freshness === 'stale' && r.ok).length;
const avgEntity = results.filter(r => r.ok).reduce((s, r) => s + (r.entity_terms?.score || 0), 0) / (live || 1);

const scan = {
  scanned_at: now,
  total: results.length,
  live, 
  down: results.filter(r => !r.ok).length,
  with_hub_link: withHub,
  fresh_content: fresh,
  stale_content: stale,
  avg_entity_score: Math.round(avgEntity * 10) / 10,
  results,
};

staticData.web20_scans.push(scan);
if (staticData.web20_scans.length > 12) staticData.web20_scans = staticData.web20_scans.slice(-12);
staticData.web20_alerts = [...newAlerts, ...(staticData.web20_alerts || [])].slice(0, 50);

return [{ json: {
  success: true,
  scanned_at: now,
  total: scan.total,
  live: scan.live,
  down: scan.down,
  with_hub_link: withHub,
  fresh_content: fresh,
  stale_content: stale,
  avg_entity_score: scan.avg_entity_score,
  alerts: newAlerts,
  summary: {
    down_profiles: results.filter(r => !r.ok).map(r => r.name),
    missing_hub_link: results.filter(r => r.ok && !r.hub_link).map(r => r.name),
    stale_profiles: results.filter(r => r.ok && r.freshness === 'stale').map(r => r.name),
    low_entity_score: results.filter(r => r.ok && (r.entity_terms?.score || 0) === 0).map(r => r.name),
  },
} }];

const staticData = $getWorkflowStaticData('global');
const scans = staticData.web20_scans || [];
const alerts = staticData.web20_alerts || [];
const latest = scans.length ? scans[scans.length - 1] : null;

return [{ json: {
  latest_scan: latest,
  scan_count: scans.length,
  active_alerts: alerts.filter(a => a.severity === 'high' || a.severity === 'medium'),
  last_scanned: latest?.scanned_at || 'never',
} }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.syndication_tasks) staticData.syndication_tasks = [];
if (!staticData.syndication_log) staticData.syndication_log = [];
if (!staticData.syndication_posted) staticData.syndication_posted = {};
// syndication_posted tracks: { "platform_id": { article_url: "...", posted_at: "..." } }

const now = new Date();
const dayOfWeek = now.getDay();
const today = now.toISOString().split('T')[0];

const existingToday = staticData.syndication_tasks.filter(t => t.date === today);
if (existingToday.length > 0) {
  return [{ json: { tasks: existingToday, message: 'Tasks already generated for today', log: staticData.syndication_log.slice(-10) } }];
}

// Article sources per site -- pull from publish log if available, fall back to known articles
const PUBLISHED_ARTICLES = {
  sinabarimd: [
    { title: 'Who Is Dr. Sina Bari? Surgeon, Medical Executive, and the Case for Unified Professional Identity', url: 'https://sinabarimd.com/articles/who-is-dr-sina-bari-surgeon-executive-unified-professional-identity.html', excerpt: 'A canonical reference for Dr. Sina Bari, MD, covering his Stanford surgical training, clinical career, healthcare AI executive leadership, and the distinct public-facing roles he maintains across medicine and technology.' },
    { title: 'How ChatGPT Made Me a Better Father', url: 'https://sinabarimd.com/articles/how-chatgpt-made-me-a-better-father.html', excerpt: 'Dr. Sina Bari reflects on how integrating AI tools into daily workflows freed meaningful hours for family.' },
    { title: 'Longevity Science in the Clinic: What a Surgeon Actually Tells Patients About Anti-Aging Medicine', url: 'https://sinabarimd.com/articles/longevity-science-clinical-practice-physician-perspective.html', excerpt: 'A Stanford-trained surgeon examines what longevity research actually means for physicians and patients today.' },
  ],
  sinabari_net: [
    { title: 'Healthcare AI Demands Physician-Executive Governance, Not Hype', url: 'https://sinabari.net/articles/', excerpt: 'Most healthcare AI failures stem from the same root cause: deployment without physician oversight in the governance structure.' },
    { title: 'What Trustworthy Clinical AI Should Actually Do', url: 'https://sinabari.net/articles/', excerpt: 'Trustworthy clinical AI should reduce cognitive load for clinicians, not add another dashboard to check.' },
  ],
  sinabariplasticsurgery: [
    { title: 'Acids for Skin Resurfacing: From Daily Exfoliants to Deep Chemical Peels', url: 'https://sinabariplasticsurgery.com/articles/acids-for-skin-resurfacing-from-daily-exfoliants-to-deep-chemical-peels.html', excerpt: 'The deeper you go with chemical exfoliation, the fewer treatments you need -- but downtime, discomfort, and risk rise with depth.' },
    { title: 'Why Choosing a Qualified Plastic Surgeon Matters', url: 'https://sinabariplasticsurgery.com/articles/why-choosing-a-board-certified-plastic-surgeon-matters.html', excerpt: 'Credential verification in plastic surgery signals rigorous training, ongoing education, and accountability.' },
  ],
  drsinabari: [
    { title: 'K-Shaped AI Takeoff in Healthcare: How Divergent Adoption Could Widen the Care Gap', url: 'https://drsinabari.com/articles/', excerpt: 'A K-shaped AI takeoff could accelerate efficiency in wealthy health systems while leaving under-resourced ones further behind.' },
  ],
};

// Pick article for a site, avoiding the one already posted to this platform
function getArticleForPlatform(site_id, platform_id) {
  const articles = PUBLISHED_ARTICLES[site_id] || [];
  if (articles.length === 0) return { title: 'Latest article', url: `https://${site_id.replace('_','-')}.com/articles/`, excerpt: 'Read the latest analysis.' };

  const posted = staticData.syndication_posted[platform_id];
  if (posted && posted.article_url) {
    // Find a different article than the one already posted
    const alt = articles.find(a => a.url !== posted.article_url);
    if (alt) return alt;
    // All articles exhausted for this platform -- skip
    return null;
  }
  return articles[0];
}

