// --- Monthly YouTube video task (first Friday of the month) ---
// Topics that lend well to video: dashboards, walkthroughs, demos, workflows, before/after, tools
const VIDEO_FRIENDLY_KEYWORDS = ['dashboard', 'walkthrough', 'workflow', 'pipeline', 'system', 'built', 'engine', 'tool', 'demo', 'setup', 'process', 'how i', 'behind the scenes', 'architecture'];

function isVideoFriendlyTopic(title, excerpt) {
  const text = ((title || '') + ' ' + (excerpt || '')).toLowerCase();
  return VIDEO_FRIENDLY_KEYWORDS.some(kw => text.includes(kw));
}

function shouldShowYouTubeTask() {
  // Only on Fridays (day 5)
  if (dayOfWeek !== 5) return false;

  // Check if we already did a YouTube task this month
  const lastYT = staticData.last_youtube_task_date;
  if (lastYT) {
    const lastDate = new Date(lastYT);
    const sameMonth = lastDate.getFullYear() === now.getFullYear() && lastDate.getMonth() === now.getMonth();
    if (sameMonth) return false;
  }

  // Only suggest if we have a video-friendly topic
  // Check across all sites for something visual
  for (const [sid, articles] of Object.entries(PUBLISHED_ARTICLES)) {
    for (const a of articles) {
      if (isVideoFriendlyTopic(a.title, a.excerpt)) return true;
    }
  }
  return false;
}

